esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS log_latency_s = MAX(AVG_OVER_TIME(ibmmq_qmgr_log_write_latency_seconds))
    BY attributes.qmgr
// Alert when average log write latency exceeds 5ms (0.005s)
// Sub-millisecond is healthy; > 1ms is warning; > 10ms is critical
// Persistent messages require synchronous log writes, so latency
// directly governs end-to-end message throughput
// Adjust threshold based on your performance requirements
| WHERE log_latency_s IS NOT NULL AND log_latency_s > 0.005
